const item = $input.first();
const body = item.json.body ?? item.json;
const treatmentId = body.treatment_id;
if (!treatmentId) {
  throw new Error('treatment_id is required');
}

const backendBaseUrl = $env.BACKEND_BASE_URL;
const nocodbBaseUrl = $env.NOCODB_BASE_URL;
const nocodbBaseId = $env.NOCODB_BASE_ID;
const nocodbToken = $env.NOCODB_API_TOKEN;
const treatmentsTableId = $env.NOCODB_TREATMENTS_TABLE_ID;
const shotsTableId = $env.NOCODB_SHOTS_TABLE_ID;

if (!backendBaseUrl || !nocodbBaseUrl || !nocodbBaseId || !nocodbToken || !treatmentsTableId || !shotsTableId) {
  throw new Error('Missing required n8n env vars for backend/NocoDB access');
}

const headers = {
  'xc-token': nocodbToken,
  'Content-Type': 'application/json',
};

const treatment = await $helpers.httpRequest({
  method: 'GET',
  url: `${backendBaseUrl}/api/treatments/${treatmentId}/json`,
  json: true,
});

const prompts = await $helpers.httpRequest({
  method: 'GET',
  url: `${backendBaseUrl}/api/treatments/${treatmentId}/prompts`,
  json: true,
});

const treatmentsUrl = `${nocodbBaseUrl}/api/v3/data/${nocodbBaseId}/${treatmentsTableId}/records`;
const shotsUrl = `${nocodbBaseUrl}/api/v3/data/${nocodbBaseId}/${shotsTableId}/records`;

const existingTreatment = await $helpers.httpRequest({
  method: 'GET',
  url: treatmentsUrl,
  json: true,
  headers,
  qs: {
    pageSize: 1,
    where: `(treatment_id,eq,${treatmentId})`,
  },
});

const treatmentFields = {
  treatment_id: treatment.id,
  title: treatment.title,
  tagline: treatment.tagline,
  structure: treatment.variables?.structure ?? null,
  structure_name: treatment.variables?.structure_name ?? null,
  collision: treatment.variables?.collision ?? null,
  director_tone: treatment.variables?.director_tone ?? null,
  product_mode: treatment.variables?.product_mode ?? null,
  location_type: treatment.location?.type ?? null,
  location_description: treatment.location?.specific_place ?? null,
  created_at: treatment.created_at,
  version: String(treatment.version ?? 1),
  treatment_json_path: `/treatments/${treatmentId}.json`,
  prompts_json_path: `/treatments/${treatmentId}_prompts.json`,
  status: 'generating',
};

let treatmentRecordId = null;
if (existingTreatment.records?.length) {
  treatmentRecordId = existingTreatment.records[0].id;
  await $helpers.httpRequest({
    method: 'PATCH',
    url: treatmentsUrl,
    json: true,
    headers,
    body: {
      id: treatmentRecordId,
      fields: treatmentFields,
    },
  });
} else {
  const createdTreatment = await $helpers.httpRequest({
    method: 'POST',
    url: treatmentsUrl,
    json: true,
    headers,
    body: {
      fields: treatmentFields,
    },
  });
  treatmentRecordId = createdTreatment.records?.[0]?.id ?? null;
}

const existingShots = await $helpers.httpRequest({
  method: 'GET',
  url: shotsUrl,
  json: true,
  headers,
  qs: {
    pageSize: 50,
    where: `(treatment_id,eq,${treatmentId})`,
  },
});

let createdShots = 0;
if (!existingShots.records?.length) {
  const shotDescriptions = new Map((treatment.shots ?? []).map((shot) => [shot.shot_number, shot]));
  const shotRecords = (prompts.shots ?? []).map((shotPrompt) => {
    const shotSpec = shotDescriptions.get(shotPrompt.shot_number) ?? {};
    return {
      fields: {
        shot_id: `${treatmentId}_s${String(shotPrompt.shot_number).padStart(2, '0')}`,
        treatment_id: treatmentId,
        shot_number: String(shotPrompt.shot_number),
        screen_position: String(shotPrompt.screen_position ?? shotSpec.screen_position ?? shotPrompt.shot_number),
        narrative_position: String(shotSpec.narrative_position ?? shotPrompt.shot_number),
        is_pivot_shot: String(Boolean(shotSpec.is_pivot_shot ?? false)),
        title: shotPrompt.title ?? shotSpec.title ?? `Shot ${shotPrompt.shot_number}`,
        prompt: shotPrompt.prompt ?? null,
        negative_prompt: shotPrompt.negative_prompt ?? prompts.negative_prompt_universal ?? null,
        image_path: null,
        image_url: null,
        model_used: prompts.model_config?.primary_model ?? 'nano-banana-pro',
        batch_variant: '1',
        generated_at: prompts.generated_at ?? treatment.created_at,
        expander_used: 'false',
        expansion_type: null,
        optimizer_cycles: '0',
        training_set_eligible: 'false',
        pivot_archive_eligible: 'false'
      }
    };
  });

  if (shotRecords.length) {
    const createdShotsResponse = await $helpers.httpRequest({
      method: 'POST',
      url: shotsUrl,
      json: true,
      headers,
      body: shotRecords,
    });
    createdShots = createdShotsResponse.records?.length ?? shotRecords.length;
  }
}

return [{
  json: {
    ok: true,
    workflow: 'new-treatment',
    treatment_id: treatmentId,
    treatment_record_id: treatmentRecordId,
    shots_existing: existingShots.records?.length ?? 0,
    shots_created: createdShots,
    message: 'Treatment ingestion completed'
  }
}];
